<script setup>
import { reactive,ref } from 'vue';import { useRoute,useRouter } from 'vue-router';import { useAuthStore } from '../stores/auth';import { submitMemberRepair } from '../api/repairApi'
const auth=useAuthStore(),route=useRoute(),router=useRouter(),saving=ref(false),error=ref(''),success=ref(''),form=reactive({brand:'',model:'',imei:'',problemDescription:'',appointmentDate:''})
async function submit(){if(!auth.isAuthenticated){router.push({path:'/login',query:{redirect:route.fullPath}});return}if(saving.value)return;error.value='';success.value='';saving.value=true;try{const data=await submitMemberRepair({...form,appointmentDate:form.appointmentDate||null});success.value=`維修申請已送出，案件編號 RP-${data.id}`;Object.assign(form,{brand:'',model:'',imei:'',problemDescription:'',appointmentDate:''})}catch(e){error.value=e.message}finally{saving.value=false}}
</script>
<template><main class="service-page"><section class="service-hero"><div class="container-wide"><span class="eyebrow">DEVICE CARE</span><h1>專業維修，進度透明可追蹤</h1><p>提供裝置資訊與問題描述，登入後即可送出申請並於會員中心掌握處理進度。</p></div></section><section class="section container-wide service-layout"><div><h2>維修申請</h2><p>送出後，服務人員會依檢測結果更新報價與處理狀態。</p><div class="trust-points"><article><strong>01</strong><h3>建立案件</h3><p>填寫裝置資訊及故障狀況。</p></article><article><strong>02</strong><h3>專業檢測</h3><p>後台更新檢測、報價與維修進度。</p></article><article><strong>03</strong><h3>會員追蹤</h3><p>登入會員中心隨時查看狀態。</p></article></div></div><form class="card service-form" @submit.prevent="submit"><h2>填寫裝置資料</h2><p v-if="error" class="alert alert-error">{{error}}</p><p v-if="success" class="alert alert-success">{{success}}</p><label>品牌<input v-model.trim="form.brand" required maxlength="60" placeholder="例如 Apple"></label><label>型號<input v-model.trim="form.model" required maxlength="120" placeholder="例如 iPhone 15"></label><label>IMEI（選填）<input v-model.trim="form.imei" maxlength="30"></label><label>希望送修日期<input v-model="form.appointmentDate" type="date"></label><label>問題描述<textarea v-model.trim="form.problemDescription" required maxlength="3000" rows="5" placeholder="請描述異常狀況、發生時間與已嘗試的處理方式"></textarea></label><button class="button button-primary button-block" :disabled="saving">{{saving?'正在送出…':auth.isAuthenticated?'送出維修申請':'登入後送出申請'}}</button></form></section></main></template>
